previewCss:
.darma-loader-darma-custom-635 {color: var(--loader-color, #6d28d9);
  --loader-secondary-color: var(--loader-secondary-color, #f0abfc);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 90px;
   height: 14px;
   box-shadow: 0 3px 0 currentColor;
   background: linear-gradient(currentColor 0 0) center/2px 100% no-repeat;
   display: grid;
}
.darma-loader-darma-custom-635:before, .darma-loader-darma-custom-635:after {
  content: "";
   grid-area: 1/1;
   background: repeating-linear-gradient(90deg,currentColor 0 14px,#0000 0 100%) 0 0/calc(100%/4) 100%;
   clip-path: inset(0 50% 0 0);
   animation: darma-loader-darma-custom-635-l2 1s infinite linear;
}
.darma-loader-darma-custom-635:before {
  background: radial-gradient(circle 7px at 7px 50%,currentColor 92%,#0000) 0 0/calc(100%/4) 100%;
   clip-path: inset(0 0 0 50%);
}
@keyframes darma-loader-darma-custom-635-l2  {
  100% {background-position: calc(100%/3) 0}
}

